    /// Returns the kernel weight for evaluation point e and data point d,
    /// applying the symmetry transformation for e >= 45.
    ///
    /// - Parameters:
    ///   - e: Evaluation point index (0-89)
    ///   - d: Data point index (0-89)
    /// - Returns: Kernel weight
    public static func getWeight(_ e: Int, _ d: Int) -> Double {
        if e < half {
            return table[d][e]
        }
        return table[n - 1 - d][n - 1 - e]
    }
